const path = require('path');
const body = $input.item.json.body || $input.item.json;

const listingId  = body.listing_id;
const imobName   = (body.imobname   || body.imobName   || '').replace(/[^a-zA-Z0-9_-]/g, '_');
const imovelRef  = (body.advertiserCode || body.imovelRef || '').replace(/[^a-zA-Z0-9_-]/g, '_');
const fps        = body.fps || 25;

const framesPath = `/data/frames/${listingId}`;
const outPath    = `/data/render/imob/${imobName}/${imovelRef}/videos/poster-${imovelRef}.mp4`;

// URLs públicas dos arquivos de áudio e legenda
const ffmpegBase = 'https://n8n-srcleads-ffmpeg-api.dtna1d.easypanel.host';
const audioUrl   = body.audio_url  || `${ffmpegBase}/data/render/imob/${imobName}/${imovelRef}/audio/narracao-${imovelRef}.mp3`;
const srtUrl     = body.srt_url    || `${ffmpegBase}/data/render/imob/${imobName}/${imovelRef}/audio/narracao-${imovelRef}.srt`;
const srtTmp     = `/tmp/narracao-${imovelRef}-${Date.now()}.srt`;

return [{ json: { listing_id: listingId, frames_path: framesPath, out_path: outPath, fps, audio_url: audioUrl, srt_url: srtUrl, srt_tmp: srtTmp, imob_name: imobName, imovel_ref: imovelRef } }];

const body       = $('Preparar caminhos').item.json;
const srtDownload = ($input.item.json.stdout || '').trim();
const hasSrt      = srtDownload === 'SRT_OK';

// Monta o filtro de legenda apenas se o SRT foi baixado com sucesso
const srtFilter   = hasSrt ? `,subtitles='${body.srt_tmp}':force_style='FontSize=22,PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,Outline=2,Shadow=1,Alignment=2'` : '';

// Escapa o caminho de saída para mkdir
const outDir = body.out_path.substring(0, body.out_path.lastIndexOf('/'));

const cmd = [
  `mkdir -p "${outDir}"`,
  `ffmpeg -y`,
  `-framerate ${body.fps}`,
  `-i "${body.frames_path}/frame_%04d.jpg"`,
  `-i "${body.audio_url}"`,
  `-vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2${srtFilter}"`,
  `-c:v libx264 -preset fast -crf 23`,
  `-c:a aac -b:a 128k`,
  `-pix_fmt yuv420p -movflags +faststart`,
  `-shortest`,
  `"${body.out_path}"`
].join(' ');

return [{ json: { ...body, cmd, has_srt: hasSrt } }];
